#include <stdio.h>
#include <fcntl.h>
#include <unistd.h>

int main() {
    int fd;
    char buffer[100];

    // System call: open() - Opens a file
    fd = open("example.txt", O_RDONLY);

    if (fd == -1) {
        perror("Error opening file");
        return 1;
    }

    // System call: read() - Reads from file descriptor
    ssize_t bytes_read = read(fd, buffer, sizeof(buffer) - 1);

    if (bytes_read == -1) {
        perror("Error reading file");
        close(fd);
        return 1;
    }

    buffer[bytes_read] = '\0';
    printf("Content: %s\n", buffer);

    // System call: close() - Closes the file descriptor
    close(fd);

    return 0;
}

/* Note: open(), read(), close() are wrapper functions 
 * that internally invoke system call instructions like
 * 'syscall' on x86-64 or 'int 0x80' on older systems */

import java.io.*;
import java.lang.Runtime;

public class SystemCallDemo {
    public static void main(String[] args) {
        // System call via ProcessBuilder
        ProcessBuilder pb = new ProcessBuilder("ls", "-la");
        pb.directory(new File("/tmp"));

        try {
            Process process = pb.start();

            // Read stdout from the process
            BufferedReader reader = new BufferedReader(
                new InputStreamReader(process.getInputStream()));
            String line;
            while ((line = reader.readLine()) != null) {
                System.out.println(line);
            }

            // Wait for process completion
            int exitCode = process.waitFor();
            System.out.println("Exit code: " + exitCode);

        } catch (IOException | InterruptedException e) {
            e.printStackTrace();
        }

        // Direct memory access (requires Unsafe class)
        // This is similar to privileged instructions
        Runtime runtime = Runtime.getRuntime();
        System.out.println("Available processors: " + 
            runtime.availableProcessors());
        System.out.println("Free memory: " + 
            runtime.freeMemory() + " bytes");
    }
}

/* Java applications interact with OS through:
 * 1. JNI (Java Native Interface) for direct system calls
 * 2. ProcessBuilder for spawning OS processes
 * 3. JVM translating bytecode to native system calls
 * 4. Native methods for platform-specific operations */
